function candidate(input) {
  if (typeof input !== "string") {
    throw new TypeError("Expected a string");
  }
  if (input.indexOf("\0") !== -1) {
    throw new TypeError("Path must not contain null bytes");
  }

  const absolute = input.charAt(0) === "/";
  const keepSlash = input.length > 0 && input.charAt(input.length - 1) === "/";
  const parts = input.split("/");
  const output = [];

  for (const part of parts) {
    if (part === "" || part === ".") {
      continue;
    }

    if (part === "..") {
      if (absolute) {
        if (output.length > 0) {
          output.pop();
        }
      } else if (output.length > 0 && output[output.length - 1] !== "..") {
        output.pop();
      } else {
        output.push(part);
      }
    } else {
      output.push(part);
    }
  }

  let normalized = output.join("/");

  if (absolute) {
    normalized = "/" + normalized;
  }

  if (normalized === "") {
    normalized = absolute ? "/" : ".";
  }

  if (keepSlash && normalized !== "/") {
    normalized += "/";
  }

  return normalized;
}
